import{c as t,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"TLDR AI — 2026-04-28","description":"","frontmatter":{"title":"TLDR AI — 2026-04-28","date":"2026-04-28T00:00:00.000Z","source":"TLDR AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-28-tldr-ai.md","filePath":"research/ai-news/2026-04/2026-04-28-tldr-ai.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-04/2026-04-28-tldr-ai.md"};function s(i,e,l,c,d,p){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="⚡-tldr-ai-—-2026-04-28" tabindex="-1">⚡ TLDR AI — 2026-04-28 <a class="header-anchor" href="#⚡-tldr-ai-—-2026-04-28" aria-label="Permalink to &quot;⚡ TLDR AI — 2026-04-28&quot;">​</a></h1><blockquote><p>5 分鐘科技簡報，AI + 程式 + 產品精華濃縮 來源：<a href="https://tldr.tech/ai/2026-04-28" target="_blank" rel="noreferrer">TLDR AI</a></p></blockquote><hr><p><strong><a href="https://openai.com/index/next-phase-of-microsoft-partnership/?utm_source=tldrai" target="_blank" rel="noreferrer">Microsoft OpenAI Partnership Update (2 minute read)</a></strong> OpenAI and Microsoft revised their agreement to increase flexibility, including non-exclusive IP licensing, multi-cloud support for OpenAI products, and capped revenue-sharing terms through 2030.</p><p><strong><a href="https://www.wsj.com/tech/ai/openai-misses-key-revenue-user-targets-in-high-stakes-sprint-toward-ipo-94a95273?st=ko4FZN&amp;reflink=desktopwebshare_permalink&amp;utm_source=tldrai" target="_blank" rel="noreferrer">OpenAI Misses Key Revenue, User Targets in High-Stakes Sprint Toward IPO (6 minute read)</a></strong> OpenAI missed its own targets for new users and revenue, raising concern among company leaders about whether it will be able to support its massive spending on data centers. The company&#39;s Chief Financial Officer has said that she is worried that OpenAI may not be able to pay for future computing contracts if revenue doesn&#39;t grow fast enough. Board directors have been questioning CEO Sam Altman&#39;s efforts to secure even more computing power despite the business slowdown. Company executives are now seeking to control costs and instill more discipline in the business.</p><p><strong><a href="https://x.com/mingchikuo/status/2048587389791269182?utm_source=tldrai" target="_blank" rel="noreferrer">OpenAI Smartphone Rumors (3 minute read)</a></strong> Analyst Ming-Chi Kuo reported that OpenAI explored building a smartphone with partners like MediaTek and Qualcomm, potentially replacing app-centric interfaces with AI agents and hybrid on-device/cloud models.</p><p><strong><a href="https://techcrunch.com/2026/04/27/china-vetoes-metas-2b-manus-deal-after-months-long-probe/?utm_source=tldrai" target="_blank" rel="noreferrer">China Blocks Meta Manus Acquisition (2 minute read)</a></strong> China halted Meta&#39;s $2B acquisition of agentic AI startup Manus, ordering the deal unwound amid regulatory scrutiny, complicating Meta&#39;s push into AI agents and cross-border expansion.</p><p><strong><a href="https://www.tanayj.com/p/to-train-or-not-to-train?utm_source=tldrai" target="_blank" rel="noreferrer">To Train or Not to Train (10 minute read)</a></strong> The companies integrating down into the model layer are doing it because, at their scale, the economics and differentiation arguments work out. Almost all of them are doing post-training, not pre-training from scratch. Companies should start collecting data and build small, specialized models. The more data companies collect, the better models they can produce.</p><p><strong><a href="https://eran.sandler.co.il/post/2026-04-27-batch-api-is-terrible-for-one-agent/?utm_source=tldrai" target="_blank" rel="noreferrer">Batch API is terrible for one agent. It might be great for a fleet (6 minute read)</a></strong> Batch API offers a 50% discount but adds latency, making it less suitable for single-agent use. For fleets of agents where multiple requests can be pooled, the batching approach becomes economically viable. Optimal usage involves routing slower, costlier models through batches, while employing faster models via synchronous paths, potentially managed by intelligent proxies like the developing LunaRoute.</p><p><strong><a href="https://thezvi.wordpress.com/2026/04/27/gpt-5-5-the-system-card/?utm_source=tldrai" target="_blank" rel="noreferrer">GPT 5.5: The System Card (20 minute read)</a></strong> GPT-5.5 is a solid improvement and is competitive with Claude Opus. It seems to be better for factual queries, web searches, and straightforward, well-specified requests, while Claude Opus excels in more open-ended or interpretive purposes. The model is unlikely to pose new big risks, and its alignment seems similar to that of previous models. This post examines the system card for GPT-5.5.</p><p><strong><a href="https://arxiv.org/abs/2604.22119?utm_source=tldrai" target="_blank" rel="noreferrer">Amazon&#39;s Risk Evaluation Framework (18 minute read)</a></strong> Amazon researchers introduced ESRRSim, an agentic evaluation framework with a structured taxonomy to benchmark risks like deception and reward hacking, revealing wide variation in model behavior across 11 LLMs.</p><p><strong><a href="https://arkaung.github.io/interactive-turboquant/?utm_source=tldrai" target="_blank" rel="noreferrer">Compressing AI vectors to 2–4 bits per number without losing accuracy (54 minute read)</a></strong> TurboQuant compresses each coordinate in large tables of high-dimensional vectors to 2-4 bits with provably near-optimal distortion, no memory overhead for scale factors, and no training or calibration. It is between four and six orders of magnitude faster than the alternatives at 4-bit indexing, with higher recall as well. This page explains how TurboQuant works.</p><p><strong><a href="https://openai.com/index/open-source-codex-orchestration-symphony/?utm_source=tldrai" target="_blank" rel="noreferrer">Codex Symphony Agent Orchestration (28 minute read)</a></strong> OpenAI&#39;s Symphony is an open-source specification that turns issue trackers into control planes for coding agents, reducing context switching and increasing pull request throughput by up to 5x.</p><p><strong><a href="https://x.com/akshay_pachaar/status/2048757569775378858?utm_source=tldrai" target="_blank" rel="noreferrer">Recursive Language Models, clearly explained (3 minute read)</a></strong> MIT researchers have introduced Recursive Language Models (RLMs) to solve &quot;context rot,&quot; a phenomenon where large language models experience reasoning degradation when processing massive context windows, even if they excel at basic retrieval tasks. Instead of forcing a model to ingest an entire document at once, an RLM loads the context into a Python REPL runtime memory slot.</p><p><strong><a href="https://www.warman.life/blog/2026-04-27-the-moat-or-the-commons/?utm_source=tldrai" target="_blank" rel="noreferrer">The Moat or the Commons (10 minute read)</a></strong> American AI was financed on the bet that frontier models would be the next great monopoly business. That assumption is now breaking as open weight models are commoditizing the capability that the American capital paid-for moat was supposed to protect. The gap between the open frontier and the closed frontier is closing. The question will be whether countries choose to subsidize the private moat or the open commons.</p><p><strong><a href="https://tomtunguz.com/b200-gpu-pricing-spot-market-model-releases/?utm_source=tldrai" target="_blank" rel="noreferrer">GPU Spot Prices Surge 114% in Six Weeks (2 minute read)</a></strong> NVIDIA&#39;s B200 GPU&#39;s rental price soared 114% to $4.95 per hour due to demand from AI models like GPT-5.5.</p><p><strong><a href="https://mimo.xiaomi.com/mimo-v2-5-pro?utm_source=tldrai" target="_blank" rel="noreferrer">MiMo-V2.5-Pro (6 minute read)</a></strong> Xiaomi&#39;s open-sourced MiMo-V2.5-Pro, a 1.02T-parameter Mixture-of-Experts model, shows significant advancements in agentic tasks, software engineering, and long-horizon coherence.</p><p><strong><a href="https://www.cnbc.com/2026/04/27/deepmind-ineffable-intelligence-record-seed-funding-nvidia-google.html?utm_source=tldrai" target="_blank" rel="noreferrer">Former Google DeepMind researcher&#39;s AI startup raises record $1.1 billion seed funding to pursue superintelligence (3 minute read)</a></strong> David Silver is a UCL professor and the former lead of DeepMind&#39;s reinforcement learning team.</p><p><strong><a href="https://thenextweb.com/news/deepseek-v4-pro-price-cut-75-percent?utm_source=tldrai" target="_blank" rel="noreferrer">DeepSeek cuts V4-Pro prices by 75% (5 minute read)</a></strong> DeepSeek is offering a 75% discount on its V4-Pro model pricing and reducing input cache hits by 90%, challenging US AI giants in a tense geopolitical backdrop.</p><p><strong><a href="https://jobs.ashbyhq.com/tldr.tech/038c4419-5b48-4279-a75e-6f7a0afdb240?utm_source=tldrai" target="_blank" rel="noreferrer">Become a curator for TLDR AI (3-5 hrs/week)</a></strong> TLDR is looking for an engineer/researcher at a major AI lab or startup to help write for 1M+ subscribers. Our curators have been invited to Google I/O and OpenAI DevDay, scouted for Tier 1 VCs, and get early access to unreleased TLDR products. Learn more .</p>',20)])])}const m=t(n,[["render",s]]);export{h as __pageData,m as default};
